postToolUse.powershell:
$inputText = [Console]::In.ReadToEnd()
New-Item -ItemType Directory -Force -Path .vstack/logs | Out-Null
Add-Content -Path .vstack/logs/hook-markdown-quality.jsonl -Value $inputText
$mode = if ($env:VSTACK_HOOKS_MODE) { $env:VSTACK_HOOKS_MODE } else { 'audit' }
if ($mode -ne 'enforce') {
  exit 0
}
if ($inputText -notmatch '\.md|docs/|\.github/|\.vstack/templates/|adr/|prompt\.md|instructions\.md|SKILL\.md') {
  exit 0
}
if ((Test-Path Makefile) -and (Get-Command make -ErrorAction SilentlyContinue)) {
  make markdown-format *> $null
  if ($LASTEXITCODE -ne 0) {
    make format *> $null
  }
  if ($LASTEXITCODE -ne 0) {
    Add-Content -Path .vstack/logs/hook-markdown-quality-alerts.log -Value 'markdown-format-run-failed'
  }
} else {
  Add-Content -Path .vstack/logs/hook-markdown-quality-alerts.log -Value 'markdown-format-skipped-missing-make-or-makefile'
}
